import './App.css';
import 'bootstrap/dist/css/bootstrap.min.css'; // Import Bootstrap CSS
import { BrowserRouter as Router, Route, Routes} from "react-router-dom";
import Navbar from './Components/NavBar.js';
import Home from './Components/Home.js';
import Analog from './Components/Analog.js';
import React, {Component} from "react";


class App extends Component {
  render() {
    const image = {
      backgroundImage: 'url(data:image/jpeg;base64,)',  
      backgroundSize: 'cover',  // Ensures the image covers the entire component
      backgroundPosition: 'center',  // Centers the image
      height: '100vh',  // Sets the height to fill the viewport
      width: '100%',  // Sets the width to fill the container
      backgroundRepeat: "no-repeat",
    };

    return (
      <div style = {image} className="App">
      <Router>
        <div>
        <Navbar/>
        <Routes>
          <Route path="/"  element={<Home/>} />
          <Route path="/analog"  element={<Analog/>} />
        </Routes>



        </div>
      </Router>
      </div>

    );
  }
}

export default App;


